import React from 'react'
import type { Page } from '../types'

interface Props {
  current: Page
  onChange: (p: Page) => void
  callbackCount: number
  recallCount: number
  username: string
  onLogout: () => void
}

export function Sidebar({ current, onChange, callbackCount, recallCount, username, onLogout }: Props) {
  const item = (page: Page, label: string, badge?: { count: number; color: 'red' | 'amber' }) => (
    <div
      className={`nav-item ${current === page ? 'active' : ''}`}
      onClick={() => onChange(page)}
    >
      {label}
      {badge && badge.count > 0 && (
        <span className={`nav-badge ${badge.color}`}>{badge.count}</span>
      )}
    </div>
  )

  return (
    <aside className="sidebar">
      <div className="sidebar-logo">
        <img
          src="data:image/png;base64,"
          alt="Flamingo Healthcare"
          style={{ height: 44, width: 44, objectFit: 'contain', background: 'white', borderRadius: 8, padding: 3, flexShrink: 0 }}
        />
        <div className="sidebar-logo-text">
          <div className="name">Flamingo</div>
          <div className="sub">Healthcare</div>
        </div>
      </div>

      <nav className="sidebar-nav">
        <div className="nav-section">Main</div>
        {item('overview', 'Overview')}
        {item('history', 'Message History')}

        <div className="nav-section">Engagement</div>
        {item('dialer', 'Dialer', { count: callbackCount, color: 'red' })}
        {item('recalls', 'Recalls', { count: recallCount, color: 'amber' })}

        <div className="nav-section">Broadcast</div>
        {item('broadcast', 'Campaigns')}
        {item('personalised', 'Personalised')}

        <div className="nav-section">Reference</div>
        {item('automations', 'Message Templates')}
      </nav>

      {/* User + logout */}
      <div style={{
        padding: '10px 14px',
        borderTop: '1px solid rgba(255,255,255,0.18)',
      }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 8 }}>
          <div>
            <div style={{ fontSize: 12.5, fontWeight: 500, color: 'rgba(255,255,255,0.85)' }}>
              {username}
            </div>
            <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.45)', marginTop: 1 }}>
              Ambattur · 044-2658 2424
            </div>
          </div>
          <button
            onClick={onLogout}
            title="Sign out"
            style={{
              background: 'rgba(255,255,255,0.12)',
              border: '1px solid rgba(255,255,255,0.2)',
              borderRadius: 6, padding: '4px 8px',
              color: 'rgba(255,255,255,0.7)', fontSize: 12,
              cursor: 'pointer', fontFamily: 'inherit',
              transition: 'all 0.15s', flexShrink: 0,
            }}
            onMouseEnter={e => {
              (e.target as HTMLButtonElement).style.background = 'rgba(255,255,255,0.22)'
              ;(e.target as HTMLButtonElement).style.color = 'white'
            }}
            onMouseLeave={e => {
              (e.target as HTMLButtonElement).style.background = 'rgba(255,255,255,0.12)'
              ;(e.target as HTMLButtonElement).style.color = 'rgba(255,255,255,0.7)'
            }}
          >
            Sign out
          </button>
        </div>
      </div>
    </aside>
  )
}
